mapper.select:
SELECT pr.id, pr.registration_id, pr.patient_id, p.patient_name,
       pr.doctor_id, d.doctor_name,
       pr.total_amount, pr.status, pr.create_time
FROM prescription pr
LEFT JOIN patient p ON pr.patient_id = p.id
LEFT JOIN doctor d ON pr.doctor_id = d.id

    AND pr.registration_id = #{registrationId}
    AND pr.patient_id = #{patientId}
    AND pr.doctor_id = #{doctorId}
    AND pr.status = #{status}

ORDER BY pr.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM prescription pr

    AND pr.registration_id = #{registrationId}
    AND pr.patient_id = #{patientId}
    AND pr.doctor_id = #{doctorId}
    AND pr.status = #{status}
